import React, { useEffect } from "react";
import { useAppDispatch, useAppSelector } from "./store/hooks/reduxHooks";

import { fetchCart, clearCart } from "./store/thunks/cartThunks";
import { removeItem } from "./store/slices/cartSlice";
import { buyCart } from "./store/thunks/cartThunks";

function CartPage() {
  const dispatch = useAppDispatch();

  const { items, total, loading, error } = useAppSelector(
    (state) => state.cart
  );

  // загрузка корзины
  useEffect(() => {
    dispatch(fetchCart());
  }, [dispatch]);

  // удаление товара (оптимистично через Redux)
  const handleRemove = (id) => {
    dispatch(removeItem(id));
    // если есть API удаление — добавь thunk позже
  };

  // покупка
  const handleBuy = async () => {
    try {
      await dispatch(buyCart()).unwrap();
      alert("✅ Покупка сохранена!");
      dispatch(fetchCart());
    } catch (error) {
      alert("❌ Ошибка: " + error);
    }
  };

  if (loading) return <p>Загрузка...</p>;
  if (error) return <p>Ошибка загрузки корзины</p>;

  return (
    <div id="content">
      <h2>Корзина</h2>

      {items.length === 0 && <p>Корзина пуста</p>}

      {items.map((item) => (
        <div key={item.id}>
          <p>
            {item.game?.title || item.item?.title} —{" "}
            {item.game?.price || item.item?.price} ₽
          </p>

          <button onClick={() => handleRemove(item.id)}>
            Удалить
          </button>
        </div>
      ))}

      <h3>Итого: {total} ₽</h3>

      <button id="buy_button" onClick={handleBuy}>
        Купить
      </button>
    </div>
  );
}

export default CartPage;
